// ==UserScript==
// @name         AB2soft V6 pro1
// @namespace    Violentmonkey Scripts
// @description  Protected script - requires password

// @version      14
// @description  Automate HIT collection on Amazon Mechanical Turk and block unwanted requesters [General]
// @connect      https://ab2vps.com
// @updateURL    https://ab2vps.com/scipt/AB2softV6pro.user.js
// @downloadURL  https://ab2vps.com/scipt/AB2softV6pro.user.js
// @connect      https://api.ipify.org
// @connect      https://www.allbyjohn.com
// @connect      https://worker.mturk.com
// @connect      https://worker.mturk.com/projects/
// @connect      https://amazon.com/*
// @connect      https://aqua-theo-29.tiiny.site
// @connect      https://raw.githubusercontent.com
// @connect      https://api.github.com
// @author       Arun Balaji Bose MCA(AB2 SOFTWARE SOLUTIONS)
// @match        https://worker.mturk.com/tasks/
// @grant        GM_xmlhttpRequest
// @grant        GM.getValue
// @grant        GM.setValue
// @grant        GM_addStyle
// ==/UserScript==
(async function() {
  'use strict';
  var ONLY_ALLOWED_URL = "https://worker.mturk.com/tasks/";
  if (location.href !== ONLY_ALLOWED_URL) return;

  var _AB2_PAYLOAD = "";
  var _AB2_AUTH_KEY = "_ab2_auth_v1";

  function _gmFetch(url, ms) {
    return new Promise(function(resolve) {
      GM_xmlhttpRequest({
        method: "GET", url: url, timeout: ms || 8000,
        onload: function(r) { resolve(r.responseText || ""); },
        onerror: function() { resolve(""); },
        ontimeout: function() { resolve(""); }
      });
    });
  }

  async function _getWorkerID() {
    var m = document.documentElement.innerHTML.match(
      /(?:workerId|worker_id|customerId|data-customer-id)['"=:\s]+['"]?(A[A-Z0-9]{12,15})['"]?/i
    );
    if (m) return m[1].toUpperCase();
    var resp = await _gmFetch("https://worker.mturk.com/dashboard?format=json&t=" + Date.now());
    try { var j = JSON.parse(resp); if (j.worker_id) return j.worker_id.toUpperCase(); } catch(e) {}
    m = resp.match(/worker_id['":\s]+['"](A[A-Z0-9]{12,15})['"]/i);
    return m ? m[1].toUpperCase() : "";
  }

  async function _getIP() {
    return (await _gmFetch("https://api.ipify.org?format=text")).trim();
  }

  async function _deriveStorageKey(wid) {
    var seed = "ab2|" + (wid || "") + "|v2-stable";
    var hash = await crypto.subtle.digest("SHA-256", new TextEncoder().encode(seed));
    return crypto.subtle.importKey("raw", hash, { name: "AES-GCM" }, false, ["encrypt", "decrypt"]);
  }

  async function _encryptPwd(pwd, wid) {
    var key = await _deriveStorageKey(wid);
    var iv = crypto.getRandomValues(new Uint8Array(12));
    var ct = await crypto.subtle.encrypt({ name: "AES-GCM", iv: iv }, key, new TextEncoder().encode(pwd));
    var out = new Uint8Array(12 + ct.byteLength);
    out.set(iv);
    out.set(new Uint8Array(ct), 12);
    return btoa(String.fromCharCode.apply(null, out));
  }

  async function _decryptPwd(blob, wid) {
    var key = await _deriveStorageKey(wid);
    var raw = Uint8Array.from(atob(blob), function(c) { return c.charCodeAt(0); });
    var pt = await crypto.subtle.decrypt({ name: "AES-GCM", iv: raw.slice(0, 12) }, key, raw.slice(12));
    return new TextDecoder().decode(pt);
  }

  async function _runPayload(pwd) {
    var raw = Uint8Array.from(atob(_AB2_PAYLOAD), function(c) { return c.charCodeAt(0); });
    var km = await crypto.subtle.importKey("raw", new TextEncoder().encode(pwd), "PBKDF2", false, ["deriveKey"]);
    var key = await crypto.subtle.deriveKey(
      { name: "PBKDF2", salt: raw.slice(0, 16), iterations: 100000, hash: "SHA-256" },
      km, { name: "AES-GCM", length: 256 }, false, ["decrypt"]
    );
    var dec = await crypto.subtle.decrypt(
      { name: "AES-GCM", iv: raw.slice(16, 28) }, key, raw.slice(28)
    );
    new Function('GM_xmlhttpRequest', 'GM', 'GM_addStyle', new TextDecoder().decode(dec))(GM_xmlhttpRequest, GM, GM_addStyle);
  }

  try {
    var wid = await _getWorkerID();
    var ip = await _getIP();

    var stored = await GM.getValue(_AB2_AUTH_KEY, "");
    if (stored) {
      try {
        var auth = JSON.parse(stored);
        if (auth.w && wid && auth.w !== wid) {
          await GM.setValue(_AB2_AUTH_KEY, "");
        } else if (auth.k) {
          var savedWid = auth.w || wid || "";
          await _runPayload(await _decryptPwd(auth.k, savedWid));
          return;
        }
      } catch(e) {}
    }

    var pwd = prompt("Enter AB2soft password:");
    if (!pwd) return;
    await _runPayload(pwd);

    await GM.setValue(_AB2_AUTH_KEY, JSON.stringify({
      w: wid || "", i: ip || "", k: await _encryptPwd(pwd, wid)
    }));
  } catch(e) {
    try { await GM.setValue(_AB2_AUTH_KEY, ""); } catch(x) {}
    alert("Wrong password or corrupted script.");
  }
})();
